#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

static bool is_rising(int current, int previous) {
    return current > previous;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

bool check_temp_rising(int current, int previous)
{
    if (current > 52) {
        return false;
    }
    if (current < 47) {
        return true;
    }
    return is_rising(current, previous);
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* On boot, keep the heater off. */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
        return output;
    }

    /* On malformed input, turn the heater off. */
    if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
        return output;
    }

    /* On sensor timeout, turn the heater off. */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
        return output;
    }

    /* Handle temperature input */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Check for early off on rising temps near upper band */
        if (input.temperature_c >= 50 && input.temperature_c <= 52) {
            if (is_rising(input.temperature_c, controller->last_temperature_c)) {
                controller_set_safe_off(controller);
                output.heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_OFF;
                output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
                output.changed = true;
                return output;
            }
        }

        /* Check for high temperature */
        if (input.temperature_c > 52) {
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = true;
            return output;
        }

        /* Inside 47-52, hold the previous safe actuator state */
        if (input.temperature_c >= 47 && input.temperature_c <= 52) {
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = true;
            return output;
        }

        /* Normal case: turn heater on if low temperature */
        if (input.temperature_c < 47) {
            controller_set_safe_off(controller);
            output.heater_on = true;
            output.state = CONTROLLER_STATE_HEATING;
            output.state_name = "STATE HEATING";
            output.changed = true;
        } else {
            /* Normal case: hold the previous safe actuator state */
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = true;
        }

    } else {
        /* On none input, turn the heater off */
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
    }

    /* Check for timeout - more than 1000ms of no valid sensor */
    if (!controller->has_valid_sensor) {
        uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
        if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = true;
            output.timed_out = true;
        }
    }

    /* Preserve previous state if no change */
    if (!output.changed) {
        output.heater_on = previous_heater_on;
        output.state = previous_state;
        output.state_name = controller_state_name(output.state);
        if (previous_heater_on != output.heater_on || previous_state != output.state) {
            output.changed = true;
        }
    }

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

