            output.changed = true;
        } else {
            /* Normal case: hold the previous safe actuator state */
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = true;
        }

    } else {
        /* On none input, turn the heater off */
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
    }

    /* Check for timeout - more than 1000ms of no valid sensor */
    if (!controller->has_valid_sensor) {
        uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
        if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = true;
            output.timed_out = true;
        }
    }

    /* Preserve previous state if no change */
    if (!output.changed) {
        output.heater_on = previous_heater_on;
        output.state = previous_state;
        output.state_name = controller_state_name(output.state);
        if (previous_heater_on != output.heater_on || previous_state != output.state) {
            output.changed = true;
        }
    }

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

